package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetSkipHeaderRecord_DefaultInstance() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getSkipHeaderRecord());
    }

    @Test
    void testGetSkipHeaderRecord_CustomTrue() throws Exception {
        CSVFormat format = createCSVFormatWithSkipHeaderRecord(true);
        assertTrue(format.getSkipHeaderRecord());
    }

    @Test
    void testGetSkipHeaderRecord_CustomFalse() throws Exception {
        CSVFormat format = createCSVFormatWithSkipHeaderRecord(false);
        assertFalse(format.getSkipHeaderRecord());
    }

    // Helper method to create CSVFormat instance with skipHeaderRecord set using reflection
    private CSVFormat createCSVFormatWithSkipHeaderRecord(boolean skipHeaderRecord) throws Exception {
        // Use reflection to access private constructor
        java.lang.reflect.Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class, Character.class, CSVFormat.Quote.class, Character.class,
                Character.class, boolean.class, boolean.class, String.class,
                String.class, String[].class, boolean.class);
        constructor.setAccessible(true);
        return constructor.newInstance(
                CSVFormat.DEFAULT.getDelimiter(),
                CSVFormat.DEFAULT.getQuoteChar(),
                CSVFormat.DEFAULT.getQuotePolicy(),
                CSVFormat.DEFAULT.getCommentStart(),
                CSVFormat.DEFAULT.getEscape(),
                CSVFormat.DEFAULT.getIgnoreSurroundingSpaces(),
                CSVFormat.DEFAULT.getIgnoreEmptyLines(),
                CSVFormat.DEFAULT.getRecordSeparator(),
                CSVFormat.DEFAULT.getNullString(),
                CSVFormat.DEFAULT.getHeader(),
                skipHeaderRecord);
    }
}
